import{_ as t,c as n,o as i,a1 as a}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Copilot: Premium Requests | opencode-mystatus","description":"Lernen Sie, wie Sie die Premium Requests-Monatsnutzung von GitHub Copilot anzeigen, Modelldetails abfragen und Übernutzung erkennen.","frontmatter":{"title":"Copilot: Premium Requests | opencode-mystatus","sidebarTitle":"Copilot-Kredit","subtitle":"Copilot: Premium Requests | opencode-mystatus","description":"Lernen Sie, wie Sie die Premium Requests-Monatsnutzung von GitHub Copilot anzeigen, Modelldetails abfragen und Übernutzung erkennen.","tags":["github-copilot","quota","premium-requests","pat-authentifizierung"],"prerequisite":["start-quick-start"],"order":3},"headers":[],"relativePath":"de/vbgate/opencode-mystatus/platforms/copilot-usage/index.md","filePath":"de/vbgate/opencode-mystatus/platforms/copilot-usage/index.md"}'),s={name:"de/vbgate/opencode-mystatus/platforms/copilot-usage/index.md"};function o(r,e,l,d,h,u){return i(),n("div",null,[...e[0]||(e[0]=[a(`<h1 id="github-copilot-kreditabfrage-premium-requests-und-modelldetails" tabindex="-1">GitHub Copilot-Kreditabfrage: Premium Requests und Modelldetails <a class="header-anchor" href="#github-copilot-kreditabfrage-premium-requests-und-modelldetails" aria-label="Permalink to &quot;GitHub Copilot-Kreditabfrage: Premium Requests und Modelldetails&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">Berechtigungsproblem der neuen OpenCode-Integration</p><p>Die neueste OAuth-Integration von OpenCode gewährt nicht mehr die Berechtigung zum Zugriff auf die <code>/copilot_internal/*</code> API, wodurch die ursprüngliche OAuth-Token-Methode keine Kredite mehr abfragen kann.</p><p>Sie können auf einen solchen Fehler stoßen:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>⚠️ GitHub Copilot-Kreditabfrage vorübergehend nicht verfügbar.</span></span>
<span class="line"><span>Die neue OAuth-Integration von OpenCode unterstützt keinen Zugriff auf die Kredit-API.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Lösung:</span></span>
<span class="line"><span>1. Erstellen Sie ein fine-grained PAT (besuchen Sie https://github.com/settings/tokens?type=beta)</span></span>
<span class="line"><span>2. Setzen Sie &#39;Plan&#39; unter &#39;Account permissions&#39; auf &#39;Read-only&#39;</span></span>
<span class="line"><span>...</span></span></code></pre></div><p>Dies ist normal, dieses Tutorial zeigt Ihnen, wie Sie das Problem lösen.</p></div><h2 id="was-sie-nach-diesem-tutorial-konnen" tabindex="-1">Was Sie nach diesem Tutorial können <a class="header-anchor" href="#was-sie-nach-diesem-tutorial-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Tutorial können&quot;">​</a></h2><ul><li>Schnell anzeigen der Premium Requests-Monatsnutzung von GitHub Copilot</li><li>Kreditunterschiede verschiedener Abonnementtypen (Free/Pro/Pro+/Business/Enterprise) verstehen</li><li>Modelldetails anzeigen (z. B. Nutzungshäufigkeit von GPT-4, Claude)</li><li>Übernutzungsanzahl erkennen und zusätzliche Kosten schätzen</li><li>Berechtigungsproblem der neuen OpenCode-Integration lösen (OAuth-Token kann keine Quote abfragen)</li></ul><h2 id="wann-sollten-sie-dies-verwenden" tabindex="-1">Wann sollten Sie dies verwenden? <a class="header-anchor" href="#wann-sollten-sie-dies-verwenden" aria-label="Permalink to &quot;Wann sollten Sie dies verwenden?&quot;">​</a></h2><p>Wenn Sie:</p><ul><li>Schnell alle Modellkredite von GitHub Copilot anzeigen möchten</li><li>Monatliche Quote planen und verschiedene Modelle nutzen möchten</li><li>Mehrere GitHub Copilot-Konten haben und einheitlich verwalten möchten</li></ul><h2 id="grundlegende-idee" tabindex="-1">Grundlegende Idee <a class="header-anchor" href="#grundlegende-idee" aria-label="Permalink to &quot;Grundlegende Idee&quot;">​</a></h2><p>GitHub Copilot bietet zwei API-Abfragemethoden, die unterschiedliche Antwortformate haben:</p><table tabindex="0"><thead><tr><th>Methode</th><th>Authentifizierung</th><th>API-Typ</th><th>Vor- und Nachteile</th></tr></thead><tbody><tr><td><strong>Public Billing API</strong> (empfohlen)</td><td>Fine-grained PAT</td><td>Öffentliche API</td><td>Stabil, detaillierte Modellnutzung, erfordert manuelle Konfiguration</td></tr><tr><td><strong>Internal API</strong> (alt)</td><td>OAuth Token</td><td>Interne API</td><td>Automatisch, keine Modelldetails, mögliche Berechtigungsprobleme</td></tr></tbody></table><h2 id="folgen-sie-mir" tabindex="-1">Folgen Sie mir <a class="header-anchor" href="#folgen-sie-mir" aria-label="Permalink to &quot;Folgen Sie mir&quot;">​</a></h2><h3 id="schritt-1-abfragebefehl-ausfuhren" tabindex="-1">Schritt 1: Abfragebefehl ausführen <a class="header-anchor" href="#schritt-1-abfragebefehl-ausfuhren" aria-label="Permalink to &quot;Schritt 1: Abfragebefehl ausführen&quot;">​</a></h3><p>Geben Sie in OpenCode den Slash-Befehl ein:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/mystatus</span></span></code></pre></div><p><strong>Was Sie sehen sollten</strong>: Die Ausgabe enthält Copilot-Kreditinformationen mit Fortschrittsbalken, verwendetem/verbleibendem Wert und Modelldetails.</p><h3 id="schritt-2-ausgabe-interpretieren" tabindex="-1">Schritt 2: Ausgabe interpretieren <a class="header-anchor" href="#schritt-2-ausgabe-interpretieren" aria-label="Permalink to &quot;Schritt 2: Ausgabe interpretieren&quot;">​</a></h3><p>Die Ausgabe enthält folgende Schlüsselinformationen:</p><p><strong>1. Kontoinformation</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Account:        GitHub Copilot (pro)</span></span></code></pre></div><p>Zeigt Ihren Copilot-Abonnementtyp (pro/free/business).</p><p><strong>2. Premium Requests-Quote</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Premium Requests [████████░░░░░░░░░░░░░] 40% (180/300)</span></span></code></pre></div><ul><li><strong>Fortschrittsbalken</strong>: Visuelle Darstellung des verbleibenden Anteils</li><li><strong>Prozent</strong>: Verbleibend 40%</li><li><strong>Verwendet/Gesamt</strong>: Verwendet 180 Mal, insgesamt 300 Mal</li></ul><p><strong>3. Modelldetails (nur öffentliche API)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Modelldetails:</span></span>
<span class="line"><span>  gpt-4: 120 Anfragen</span></span>
<span class="line"><span>  claude-3.5-sonnet: 60 Anfragen</span></span></code></pre></div><p>Zeigt die Nutzungshäufigkeit jedes Modells, absteigend nach Nutzung (maximal 5 angezeigt).</p><div class="info custom-block"><p class="custom-block-title">Warum zeigt meine Ausgabe keine Modelldetails?</p><p>Modelldetails werden nur angezeigt, wenn die öffentliche API (Fine-grained PAT) verwendet wird. Bei Verwendung von OAuth-Token (interne API) werden keine Modelldetails angezeigt.</p></div><p><strong>4. Übernutzung (falls vorhanden)</strong></p><p>Wenn Sie die monatliche Quote überschreiten, wird Folgendes angezeigt:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Übernutzung: 25 Anfragen</span></span></code></pre></div><p>Übernutzung verursacht zusätzliche Kosten, die Tarife finden Sie in den GitHub Copilot-Preisen.</p><p><strong>5. Rücksetzzeit (nur interne API)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Quoterücksetzung: 12d 5h (2026-02-01)</span></span></code></pre></div><p>Zeigt den Countdown bis zur nächsten Quoterücksetzung.</p><h2 id="haufige-fehler" tabindex="-1">Häufige Fehler <a class="header-anchor" href="#haufige-fehler" aria-label="Permalink to &quot;Häufige Fehler&quot;">​</a></h2><h3 id="haufigster-fehler-oauth-token-kann-keine-quote-abfragen" tabindex="-1">Häufigster Fehler: OAuth-Token kann keine Quote abfragen <a class="header-anchor" href="#haufigster-fehler-oauth-token-kann-keine-quote-abfragen" aria-label="Permalink to &quot;Häufigster Fehler: OAuth-Token kann keine Quote abfragen&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">Häufiger Fehler</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>⚠️ GitHub Copilot-Kreditabfrage vorübergehend nicht verfügbar.</span></span>
<span class="line"><span>Die neue OAuth-Integration von OpenCode unterstützt keinen Zugriff auf die Kredit-API.</span></span></code></pre></div><p><strong>Ursache</strong>: Die OAuth-Integration von OpenCode gewährt keine <code>/copilot_internal/*</code> API-Berechtigung.</p><p><strong>Lösung</strong>: Verwenden Sie die Methode 1 (Fine-grained PAT) gemäß der Konfiguration.</p></div><h3 id="fehler-2-formatfehler-der-konfigurationsdatei" tabindex="-1">Fehler 2: Formatfehler der Konfigurationsdatei <a class="header-anchor" href="#fehler-2-formatfehler-der-konfigurationsdatei" aria-label="Permalink to &quot;Fehler 2: Formatfehler der Konfigurationsdatei&quot;">​</a></h3><p>Wenn die Konfigurationsdatei <code>~/.config/opencode/copilot-quota-token.json</code> falsch formatiert ist, schlägt die Abfrage fehl.</p><p><strong>Lösung</strong>: Stellen Sie sicher, dass die Datei folgende Felder enthält:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;github_pat_abc123&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;username&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;johndoe&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tier&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;pro&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="fehler-3-falscher-abonnementtyp" tabindex="-1">Fehler 3: Falscher Abonnementtyp <a class="header-anchor" href="#fehler-3-falscher-abonnementtyp" aria-label="Permalink to &quot;Fehler 3: Falscher Abonnementtyp&quot;">​</a></h3><p>Wenn das Feld <code>tier</code> nicht mit Ihrem tatsächlichen Abonnement übereinstimmt, wird die Quotaberechnung falsch.</p><p><strong>Abonnementtyp-Tabelle</strong>:</p><table tabindex="0"><thead><tr><th>Ihr tatsächliches Abonnement</th><th>tier-Feld sollte sein</th><th>Falsches Beispiel</th></tr></thead><tbody><tr><td>Free</td><td><code>free</code></td><td><code>pro</code> ❌</td></tr><tr><td>Pro</td><td><code>pro</code></td><td><code>free</code> ❌</td></tr><tr><td>Pro+</td><td><code>pro+</code></td><td><code>pro</code> ❌</td></tr><tr><td>Business</td><td><code>business</code></td><td><code>enterprise</code> ❌</td></tr><tr><td>Enterprise</td><td><code>enterprise</code></td><td><code>business</code> ❌</td></tr></tbody></table><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><ul><li><strong>Premium Requests</strong> ist die Hauptquote-Kennzahl von Copilot</li><li><strong>Abonnementtypen</strong> bestimmen die monatliche Quote: Free 50, Pro 300, Pro+ 1500, Business 300, Enterprise 1000</li><li><strong>Übernutzung</strong> verursacht zusätzliche Kosten</li><li><strong>Fine-grained PAT</strong> ist die empfohlene Authentifizierungsmethode</li><li><strong>OAuth-Token</strong> kann aufgrund von Berechtigungsproblemen fehlschlagen</li></ul><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../google-usage/">Google Cloud-Kreditabfrage</a></strong>.</p><p>Sie werden lernen:</p><ul><li>4 Modelle (G3 Pro, G3 Image, G3 Flash, Claude) und deren Unterschiede</li><li>Verwaltung mehrerer Konten</li><li>Authentifizierungsdateilesemmechanismus</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie hier, um die Quellcodepositionen anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>Wichtige Konstanten</strong>:</p><ul><li><code>COPILOT_PLAN_LIMITS</code>: Monatliche Quoten verschiedener Abonnementtypen (Zeilen 397-403) <ul><li><code>free: 50</code></li><li><code>pro: 300</code></li><li><code>pro+: 1500</code></li><li><code>business: 300</code></li><li><code>enterprise: 1000</code></li></ul></li></ul></details>`,52)])])}const g=t(s,[["render",o]]);export{c as __pageData,g as default};
